package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the aliyun command with arguments passed directly (no shell injection)
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Get stdout pipe from aliyun command
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}

	// Capture stderr from aliyun
	var aliyunStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Create the jq command with stdin connected to aliyun's stdout
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = aliyunStdout

	// Capture jq's output and stderr
	var jqOutput, jqStderr bytes.Buffer
	jqCmd.Stdout = &jqOutput
	jqCmd.Stderr = &jqStderr

	// Run jq (this will read from the pipe until EOF)
	jqErr := jqCmd.Run()

	// Wait for aliyun to finish (must do this regardless of jq error to avoid zombie process)
	aliyunErr := aliyunCmd.Wait()

	// Check for errors
	if aliyunErr != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", aliyunErr, aliyunStderr.String())
	}

	if jqErr != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", jqErr, jqStderr.String())
	}

	// Write output to file using Go's file I/O (no shell redirection)
	output := jqOutput.String()
	if err := os.WriteFile(outputFile, []byte(output), 0644); err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return output, nil
}

func main() {
	// Example usage
	output, err := QuerySLBAndExport("my-load-balancer", "output.json")
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Successfully exported SLB info. Output length: %d bytes\n", len(output))
}

