package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport queries SLB information using aliyun CLI and exports formatted output using jq.
// It runs the command: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > output.json
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the first command: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME
	cmd1 := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the second command: jq '.LoadBalancers.LoadBalancer[]'
	cmd2 := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Get the stdout pipe from the first command
	stdoutPipe, err := cmd1.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}

	// Connect the stdout of cmd1 to stdin of cmd2
	cmd2.Stdin = stdoutPipe

	// Capture the output of the second command
	var output bytes.Buffer
	cmd2.Stdout = &output

	// Start the second command first (it will wait for input on stdin)
	if err := cmd2.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Start the first command
	if err := cmd1.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Wait for the first command to complete
	if err := cmd1.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Wait for the second command to complete
	if err := cmd2.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Get the output string
	result := output.String()

	// Write output to file
	if err := os.WriteFile(outputFile, output.Bytes(), 0644); err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return result, nil
}

func main() {
	// Example usage
	loadBalancerName := "my-load-balancer"
	outputFile := "output.json"

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Successfully exported SLB information to %s\n", outputFile)
	fmt.Println("Result:")
	fmt.Println(result)
}

