	// Run the second command (this will read from cmd1's stdout)
	if err := cmd2.Run(); err != nil {
		cmd1.Wait()
		return stderr.String(), fmt.Errorf("jq command failed: %w", err)
	}

	// Wait for the first command to complete
	if err := cmd1.Wait(); err != nil {
		return stderr.String(), fmt.Errorf("aliyun command failed: %w", err)
	}

	// Write the formatted output to the specified file
	if err := os.WriteFile(outputFile, output.Bytes(), 0644); err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return output.String(), nil
}

func main() {
	// Example usage
	loadBalancerName := "my-load-balancer"
	outputFile := "output.json"

