package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic input validation
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Create the aliyun command with proper argument separation (no shell injection)
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command with proper argument separation
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Set up pipe between commands: aliyun stdout -> jq stdin
	stdoutPipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	jqCmd.Stdin = stdoutPipe

	// Capture jq output
	var output bytes.Buffer
	jqCmd.Stdout = &output

	// Capture stderr from both commands
	var aliyunStderr, jqStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stderr = &jqStderr

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Run jq command (will read from aliyun's stdout via pipe)
	jqErr := jqCmd.Run()

	// Wait for aliyun to complete (always wait to avoid zombie process)
	aliyunErr := aliyunCmd.Wait()

	// Check for errors
	if aliyunErr != nil {
		combinedStderr := aliyunStderr.String() + jqStderr.String()
		return combinedStderr, fmt.Errorf("aliyun command failed: %w, stderr: %s", aliyunErr, combinedStderr)
	}

	if jqErr != nil {
		combinedStderr := aliyunStderr.String() + jqStderr.String()
		return combinedStderr, fmt.Errorf("jq command failed: %w, stderr: %s", jqErr, combinedStderr)
	}

	// Write output to file
	if err := os.WriteFile(outputFile, output.Bytes(), 0644); err != nil {
		return output.String(), fmt.Errorf("failed to write output file: %w", err)
	}

	return output.String(), nil
}

func main() {
	// Example usage
	result, err := QuerySLBAndExport("my-load-balancer", "output.json")
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Result: %s\n", result)
}

