package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Run aliyun command with explicit arguments (no shell interpolation)
	// This prevents command injection by avoiding shell interpretation
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	var aliyunStdout, aliyunStderr bytes.Buffer
	aliyunCmd.Stdout = &aliyunStdout
	aliyunCmd.Stderr = &aliyunStderr

	if err := aliyunCmd.Run(); err != nil {
		combinedOutput := aliyunStdout.String() + aliyunStderr.String()
		return combinedOutput, fmt.Errorf("aliyun command failed: %w, output: %s", err, combinedOutput)
	}

	// Run jq command with aliyun output as input
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = bytes.NewReader(aliyunStdout.Bytes())

	var jqStdout, jqStderr bytes.Buffer
	jqCmd.Stdout = &jqStdout
	jqCmd.Stderr = &jqStderr

	if err := jqCmd.Run(); err != nil {
		combinedOutput := jqStdout.String() + jqStderr.String()
		return combinedOutput, fmt.Errorf("jq command failed: %w, output: %s", err, combinedOutput)
	}

	// Write to file using Go's file I/O instead of shell redirection
	if err := os.WriteFile(outputFile, jqStdout.Bytes(), 0644); err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return jqStdout.String(), nil
}

func main() {
	// Example usage
	result, err := QuerySLBAndExport("my-load-balancer", "output.json")
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}
	fmt.Println(result)
}

