package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate and clean the output file path to prevent path traversal
	outputFile = filepath.Clean(outputFile)
	if outputFile == "" || outputFile == "." || outputFile == ".." {
		return "", fmt.Errorf("invalid output file path")
	}

	// Additional validation: prevent absolute paths to sensitive directories if needed
	if strings.HasPrefix(outputFile, "/etc/") || strings.HasPrefix(outputFile, "/root/") {
		return "", fmt.Errorf("output file path not allowed")
	}

	// Create the aliyun command with proper argument separation
	// Using exec.Command with individual arguments prevents shell injection
	// as arguments are passed directly to execve, not interpreted by shell
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Capture the output from aliyun command
	aliyunOutput, err := aliyunCmd.Output()
	if err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, string(exitErr.Stderr))
		}
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Create the jq command and pipe the output from aliyun
	// The jq filter is hardcoded and safe
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = bytes.NewReader(aliyunOutput)

	// Capture the output from jq
	jqOutput, err := jqCmd.Output()
	if err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, string(exitErr.Stderr))
		}
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Write output to file with appropriate permissions
	// Handle file redirection in Go instead of shell
	if err := os.WriteFile(outputFile, jqOutput, 0644); err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return string(jqOutput), nil
}

