func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Build the command string with shell pipeline
	cmdStr := fmt.Sprintf(
		"aliyun slb DescribeLoadBalancers --LoadBalancerName %s | jq '.LoadBalancers.LoadBalancer[]' > %s",
		loadBalancerName, outputFile,
	)

	// Execute the command using shell to support pipeline and redirection
	cmd := exec.Command("sh", "-c", cmdStr)

	// Capture combined output (stdout + stderr)
	// Note: stdout is redirected to outputFile, so this mainly captures stderr
	output, err := cmd.CombinedOutput()
	if err != nil {
		return string(output), fmt.Errorf("command execution failed: %v", err)
	}

	return string(output), nil
}

