// QuerySLBAndExport queries SLB information using the aliyun CLI and exports it to a JSON file.
// It executes the equivalent of: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > outputFile
// Returns a success message or an error if any step fails.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the first command: aliyun slb DescribeLoadBalancers --LoadBalancerName <name>
	cmd1 := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Buffer to capture stderr from aliyun command for error reporting
	var cmd1Stderr bytes.Buffer
	cmd1.Stderr = &cmd1Stderr

	// Create the second command: jq '.LoadBalancers.LoadBalancer[]'
	cmd2 := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Buffer to capture stderr from jq command for error reporting
	var cmd2Stderr bytes.Buffer
	cmd2.Stderr = &cmd2Stderr

	// Create a pipe to connect cmd1's stdout to cmd2's stdin
	// This implements the | in the pipeline
	pipe, err := cmd1.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}
	cmd2.Stdin = pipe

	// Create/open the output file for writing
	// This implements the > outputFile redirection
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer file.Close()

	// Redirect cmd2's stdout to the output file
	cmd2.Stdout = file

	// Start the aliyun command (non-blocking)
	if err := cmd1.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Run the jq command (blocking - waits for completion)
	// jq will read from the pipe connected to aliyun's stdout
	if err := cmd2.Run(); err != nil {
		return "", fmt.Errorf("failed to run jq command: %w, stderr: %s", err, cmd2Stderr.String())
	}

	// Wait for the aliyun command to complete
	if err := cmd1.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, cmd1Stderr.String())
	}

	return fmt.Sprintf("SLB information exported to %s", outputFile), nil
}

func main() {
	// Example usage
	loadBalancerName := "my-load-balancer"
	outputFile := "output.json"

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}
	fmt.Println(result)
}

