	}
	if strings.ContainsAny(outputFile, dangerousChars) {
		return "", fmt.Errorf("invalid characters in outputFile")
	}

	// Create the aliyun command with arguments passed directly (not through shell)
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Get stdout pipe from aliyun command to pipe to jq
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
