package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Input validation
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Run the aliyun command and capture its output
	// Using exec.Command with individual arguments prevents shell injection
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	aliyunOutput, err := aliyunCmd.Output()
	if err != nil {
		var stderr string
		if exitErr, ok := err.(*exec.ExitError); ok {
			stderr = string(exitErr.Stderr)
		}
		return stderr, fmt.Errorf("aliyun command failed: %w", err)
	}

	// Run jq with the aliyun output as input
	// Pipe the output using bytes.NewReader instead of shell piping
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = bytes.NewReader(aliyunOutput)

	jqOutput, err := jqCmd.Output()
	if err != nil {
		var stderr string
		if exitErr, ok := err.(*exec.ExitError); ok {
			stderr = string(exitErr.Stderr)
		}
		return stderr, fmt.Errorf("jq command failed: %w", err)
	}

	// Write output to file using Go's file operations instead of shell redirection
	outputStr := string(jqOutput)
	err = os.WriteFile(outputFile, jqOutput, 0644)
	if err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return outputStr, nil
}

func main() {
	// Example usage
	result, err := QuerySLBAndExport("my-load-balancer", "output.json")
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		if result != "" {
			fmt.Printf("Output: %s\n", result)
		}
		return
	}
	fmt.Println("Success! Output written to output.json")
	fmt.Printf("Result: %s\n", result)
}

