package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the aliyun command
	// Arguments are passed directly to the command without shell interpolation,
	// which prevents shell injection attacks
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Capture aliyun stdout and stderr separately
	var aliyunStdout, aliyunStderr bytes.Buffer
	aliyunCmd.Stdout = &aliyunStdout
	aliyunCmd.Stderr = &aliyunStderr

	// Run aliyun command
	if err := aliyunCmd.Run(); err != nil {
		return aliyunStderr.String(), fmt.Errorf("aliyun command failed: %w", err)
	}

	// Create jq command with aliyun output as input
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = &aliyunStdout

	// Capture jq stdout and stderr separately
	var jqStdout, jqStderr bytes.Buffer
	jqCmd.Stdout = &jqStdout
	jqCmd.Stderr = &jqStderr

	// Run jq command
	if err := jqCmd.Run(); err != nil {
		return jqStderr.String(), fmt.Errorf("jq command failed: %w", err)
	}

	// Write output to file using Go's native file operations
	if err := os.WriteFile(outputFile, jqStdout.Bytes(), 0644); err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return jqStdout.String(), nil
}

func main() {
	// Example usage
	result, err := QuerySLBAndExport("my-load-balancer", "output.json")
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}
	fmt.Println("Command output:")
	fmt.Println(result)
}

