	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command to format JSON output
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Connect cmdAliyun's stdout to cmdJq's stdin using a pipe
	stdoutPipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	cmdJq.Stdin = stdoutPipe

	// Create the output file for writing results
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file %s: %w", outputFile, err)
	}
	defer outFile.Close()
	cmdJq.Stdout = outFile

	// Capture stderr from both commands for error reporting
	var stderrBuf bytes.Buffer
	cmdAliyun.Stderr = &stderrBuf
	cmdJq.Stderr = &stderrBuf

