func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate loadBalancerName - use whitelist approach: only allow alphanumeric, hyphens, underscores, and dots
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	validName := regexp.MustCompile(`^[a-zA-Z0-9._-]+$`)
	if !validName.MatchString(loadBalancerName) {
