	}

	// Validate outputFile
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Clean the path to normalize it
	cleanPath := filepath.Clean(outputFile)

	// Check for path traversal attempts
	if strings.Contains(cleanPath, "..") {
		return "", fmt.Errorf("invalid output file path: path traversal not allowed")
	}

	// Validate path characters - only allow safe characters
	validPath := regexp.MustCompile(`^[a-zA-Z0-9._/-]+$`)
	if !validPath.MatchString(cleanPath) {
		return "", fmt.Errorf("invalid characters in outputFile path")
	}

	// Execute aliyun command directly without shell - arguments are passed safely
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Capture stdout and stderr separately
	var aliyunStdout bytes.Buffer
	var aliyunStderr bytes.Buffer
	aliyunCmd.Stdout = &aliyunStdout
	aliyunCmd.Stderr = &aliyunStderr

	if err := aliyunCmd.Run(); err != nil {
		return aliyunStderr.String(), fmt.Errorf("aliyun command failed: %w", err)
	}

	// Execute jq command with aliyun's stdout as input - no shell involved
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = &aliyunStdout

	var jqStdout bytes.Buffer
	var jqStderr bytes.Buffer
	jqCmd.Stdout = &jqStdout
	jqCmd.Stderr = &jqStderr

	if err := jqCmd.Run(); err != nil {
		return jqStderr.String(), fmt.Errorf("jq command failed: %w", err)
	}

	// Write to output file directly using Go's file I/O instead of shell redirection
	if err := os.WriteFile(cleanPath, jqStdout.Bytes(), 0644); err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return jqStdout.String(), nil
}

func main() {
