package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the first command (aliyun) with proper argument passing (no shell interpolation)
	cmd1 := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the second command (jq)
	cmd2 := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Set up pipe between commands: cmd1's stdout -> cmd2's stdin
	pipeReader, err := cmd1.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}
	cmd2.Stdin = pipeReader

	// Capture stderr from both commands for error reporting
	var stderr1, stderr2 bytes.Buffer
	cmd1.Stderr = &stderr1
	cmd2.Stderr = &stderr2

	// Capture output from jq
	var output bytes.Buffer
	cmd2.Stdout = &output

	// Start the second command first (consumer must be ready before producer starts)
	if err := cmd2.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq: %w", err)
	}

	// Start the first command (producer)
	if err := cmd1.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun: %w", err)
	}

	// Wait for the first command to complete
	if err := cmd1.Wait(); err != nil {
		return stderr1.String(), fmt.Errorf("aliyun command failed: %w, stderr: %s", err, stderr1.String())
	}

	// Wait for the second command to complete
	if err := cmd2.Wait(); err != nil {
		return output.String() + stderr2.String(), fmt.Errorf("jq command failed: %w, stderr: %s", err, stderr2.String())
	}

	// Write output to file using Go's file operations (no shell redirection)
	if err := os.WriteFile(outputFile, output.Bytes(), 0644); err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return output.String(), nil
}

